import { useLocation } from "react-router-dom";
import styled from "styled-components";

const allProducts = [
  { id: 1, name: "iPhone 15", category: "celular" ,  price: 5999,
    oldPrice: 6999,
    image: "https://via.placeholder.com/300"},
  { id: 2, name: "Galaxy S23", category: "celular" },
  { id: 3, name: "JBL 520BT", category: "headphone" },
  { id: 4, name: "Notebook Gamer", category: "notebook" },
  { id: 5, name: "Mouse RGB", category: "acessorios" }
];

const Products = () => {
  const location = useLocation();
  const queryParams = new URLSearchParams(location.search);
  const categoria = queryParams.get("categoria");

  const filteredProducts = categoria
    ? allProducts.filter(p => p.category === categoria)
    : allProducts;

  return (
    <Container>
      <Title>
        {categoria ? `Categoria: ${categoria}` : "Todos os Produtos"}
      </Title>

      <Grid>
        {filteredProducts.map((product) => (
          <Card key={product.id}>
            {product.name}
          </Card>
        ))}
      </Grid>
    </Container>
  );
};

export default Products;

const Container = styled.div`
  padding: 120px 80px;
  background: #0D0D0D;
  min-height: 100vh;
`;

const Title = styled.h1`
  font-family: 'Space Grotesk', sans-serif;
  color: white;
  margin-bottom: 40px;
`;

const Grid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
  gap: 30px;
`;

const Card = styled.div`
  background: #1A1A1A;
  padding: 40px;
  border-radius: 16px;
  color: white;
  transition: 0.3s;

  &:hover {
    background: #222;
  }
`;
